import { Component, OnInit } from '@angular/core';
import { PantryService } from '../../../services/pantry.service';
import { HouseholdService } from '../../../services/household.service';
import { PantryItem, Category, Household } from '../../../models/models';

@Component({
  selector: 'app-pantry-list',
  templateUrl: './pantry-list.component.html',
  styleUrls: ['./pantry-list.component.css']
})


export class PantryListComponent implements OnInit {
  items: PantryItem[] = [];
  categories: Category[] = [];
  household: Household | null = null;
  loading = true;

  //filters
  searchTerm = '';
  statusFilter = '';
  categoryFilter = '';
  sortBy = 'name';
  showExpiringSoon = false;

  //modal state
  showForm = false;
  editItem: PantryItem | null = null;
  showConsumeModal = false;
  showWasteModal = false;
  actionItem: PantryItem | null = null;
  actionQty = 1;

  constructor(
    private pantryService: PantryService,
    private householdService: HouseholdService
  ) {}

  ngOnInit(): void {
    this.householdService.selectedHousehold$.subscribe(h => {
      this.household = h;
      if (h) this.load();
      else this.loading = false;
    });
    this.pantryService.getCategories().subscribe({
      next: res => { this.categories = res.results; }
    });
  }

  load(): void {
    if (!this.household) return;
    this.loading = true;
    this.pantryService.getItems({
      household_id: this.household.id,
      search: this.searchTerm,
      status: this.statusFilter,
      category_id: this.categoryFilter ? Number(this.categoryFilter) : undefined,
      ordering: this.sortBy,
      expiring_soon: this.showExpiringSoon || undefined,
    }).subscribe({
      next: res => { this.items = res.results; this.loading = false; },
      error: () => { this.loading = false; }
    });
  }

  onSearch(): void { this.load(); }
  onFilterChange(): void { this.load(); }

  openAdd(): void { this.editItem = null; this.showForm = true; }
  openEdit(item: PantryItem): void { this.editItem = item; this.showForm = true; }

  onFormSaved(): void {
    this.showForm = false;
    this.editItem = null;
    this.load();
  }

  openConsume(item: PantryItem): void {
    this.actionItem = item;
    this.actionQty = item.quantity;
    this.showConsumeModal = true;
  }

  openWaste(item: PantryItem): void {
    this.actionItem = item;
    this.actionQty = item.quantity;
    this.showWasteModal = true;
  }

  confirmConsume(): void {
    if (!this.actionItem) return;
    this.pantryService.consumeItem(this.actionItem.id, this.actionQty).subscribe({
      next: () => { this.showConsumeModal = false; this.load(); }
    });
  }

  confirmWaste(): void {
    if (!this.actionItem) return;
    this.pantryService.wasteItem(this.actionItem.id, this.actionQty).subscribe({
      next: () => { this.showWasteModal = false; this.load(); }
    });
  }

  deleteItem(item: PantryItem): void {
    if (!confirm('Delete "' + item.name + '"?')) return;
    this.pantryService.deleteItem(item.id).subscribe({
      next: () => this.load()
    });
  }

  getStatusClass(item: PantryItem): string {
    if (item.is_expired) return 'badge badge-danger';
    if (item.days_until_expiry !== null && item.days_until_expiry <= 3) return 'badge badge-warning';
    const map: Record<string, string> = {
      available: 'badge status-available',
      low: 'badge status-low',
      consumed: 'badge status-consumed',
      wasted: 'badge status-wasted',
    };
    return map[item.status] || 'badge badge-muted';
  }

  getExpiryLabel(item: PantryItem): string {
    if (!item.expiry_date) return '-';
    if (item.is_expired) return 'Expired';
    if (item.days_until_expiry === 0) return 'Today';
    if (item.days_until_expiry === 1) return 'Tomorrow';
    if (item.days_until_expiry !== null && item.days_until_expiry <= 7)
      return `${item.days_until_expiry}d`;
    return item.expiry_date.slice(0, 10);
  }

  canWrite(): boolean {
    const role = this.household?.current_user_role;
    return role === 'admin' || role === 'inventory_manager';
  }
}
<div class="container pantry-page">

  <!-- no household -->
  <div *ngIf="!household && !loading" class="empty-state card">
    <h3>No household selected</h3>
    <p>Select a household from the navigation bar</p>
    <a routerLink="/households" class="btn btn-primary" style="margin-top:1rem">Go to Households</a>
  </div>

  <ng-container *ngIf="household">
    <div class="page-header">
      <h1>Pantry - {{ household.name }}</h1>
      <button class="btn btn-primary" (click)="openAdd()" *ngIf="canWrite()">+ Add Item</button>
    </div>

    <!-- filters -->
    <div class="filters card">
      <div class="filters-row">
        <input class="form-control" [(ngModel)]="searchTerm"
          (ngModelChange)="onSearch()" placeholder="🔍 Search items...">

        <select class="form-control" [(ngModel)]="statusFilter" (ngModelChange)="onFilterChange()">
          <option value="">All statuses</option>
          <option value="available">Available</option>
          <option value="low">Low Stock</option>
          <option value="consumed">Consumed</option>
          <option value="wasted">Wasted</option>
        </select>

        <select class="form-control" [(ngModel)]="categoryFilter" (ngModelChange)="onFilterChange()">
          <option value="">All categories</option>
          <option *ngFor="let cat of categories" [value]="cat.id">
            {{ cat.name }}
          </option>
        </select>

        <select class="form-control" [(ngModel)]="sortBy" (ngModelChange)="onFilterChange()">
          <option value="name">Sort: Name</option>
          <option value="expiry_date">Sort: Expiry</option>
          <option value="-added_at">Sort: Newest</option>
          <option value="quantity">Sort: Quantity</option>
        </select>

        <label class="expiry-toggle">
          <input type="checkbox" [(ngModel)]="showExpiringSoon" (ngModelChange)="onFilterChange()">
            Expiring soon
        </label>
      </div>
    </div>

    <div *ngIf="loading" class="spinner"></div>

    <!-- empty -->
    <div *ngIf="!loading && items.length === 0" class="empty-state card">
      <h3>No items found</h3>
      <p>Try adjusting your filters or add new items</p>
      <button class="btn btn-primary" style="margin-top:1rem"
        (click)="openAdd()" *ngIf="canWrite()">Add First Item</button>
    </div>


    <div class="card table-wrap" *ngIf="!loading && items.length > 0">
      <table>
        <thead>
          <tr>
            <th>Item</th>
            <th>Category</th>
            <th>Quantity</th>
            <th>Expiry</th>
            <th>Status</th>
            <th>Added by</th>
            <th *ngIf="canWrite()">Actions</th>
          </tr>
        </thead>
        <tbody>
          <tr *ngFor="let item of items" [class.row-expired]="item.is_expired">
            <td>
              <div class="item-name">{{ item.name }}</div>
              <div class="text-sm text-muted" *ngIf="item.notes">{{ item.notes }}</div>
            </td>
            <td>
              <span *ngIf="item.category">{{ item.category.name }}</span>
              <span *ngIf="!item.category" class="text-muted">-</span>
            </td>
            <td>{{ item.quantity }} {{ item.unit }}</td>
            <td>
              <span [class]="getStatusClass(item)" *ngIf="item.expiry_date">
                {{ getExpiryLabel(item) }}
              </span>
              <span *ngIf="!item.expiry_date" class="text-muted">-</span>
            </td>
            <td>
              <span [class]="'badge status-' + item.status">{{ item.status }}</span>
            </td>
            <td class="text-sm text-muted">{{ item.added_by?.username || '-' }}</td>
            <td *ngIf="canWrite()">
              <div class="action-btns">
                <button class="btn btn-sm btn-outline" title="Edit" (click)="openEdit(item)">Edit</button>
                <button class="btn btn-sm btn-secondary" title="Consume" (click)="openConsume(item)"
                  [disabled]="item.status !== 'available'">Consume</button>
                <button class="btn btn-sm btn-warning" title="Mark as wasted" (click)="openWaste(item)"
                  [disabled]="item.status !== 'available'">Mark as Wasted</button>
                <button class="btn btn-sm btn-danger" title="Delete" (click)="deleteItem(item)">Delete</button>
              </div>
            </td>
          </tr>
        </tbody>
      </table>
    </div>
  </ng-container>

  <!-- Add / Edit  modal -->
  <app-pantry-item-form
    *ngIf="showForm && household"
    [household]="household"
    [item]="editItem"
    [categories]="categories"
    (saved)="onFormSaved()"
    (cancelled)="showForm = false">
  </app-pantry-item-form>

  <!-- consume modal -->
  <div class="modal-overlay" *ngIf="showConsumeModal" (click)="showConsumeModal = false">
    <div class="modal" (click)="$event.stopPropagation()">
      <div class="modal-header">
        <h2>Consume "{{ actionItem?.name }}"</h2>
        <button class="modal-close" (click)="showConsumeModal = false">x</button>
      </div>
      <div class="form-group">
        <label>Quantity to consume (max {{ actionItem?.quantity }} {{ actionItem?.unit }})</label>
        <input class="form-control" type="number" [(ngModel)]="actionQty"
          [max]="actionItem ? actionItem.quantity : null"  min="0.01" step="any">
      </div>
      <div class="modal-footer">
        <button class="btn btn-secondary" (click)="showConsumeModal = false">Cancel</button>
        <button class="btn btn-primary" (click)="confirmConsume()">Confirm</button>
      </div>
    </div>
  </div>

  <!-- waste modal -->
  <div class="modal-overlay" *ngIf="showWasteModal" (click)="showWasteModal = false">
    <div class="modal" (click)="$event.stopPropagation()">
      <div class="modal-header">
        <h2>Waste "{{ actionItem?.name }}"</h2>
        <button class="modal-close" (click)="showWasteModal = false">x</button>
      </div>
      <div class="form-group">
        <label>Quantity to mark as wasted (max {{ actionItem?.quantity }} {{ actionItem?.unit }})</label>
        <input class="form-control" type="number" [(ngModel)]="actionQty"
          [max]="actionItem ? actionItem.quantity : null"  min="0.01" step="any">
      </div>
      <div class="modal-footer">
        <button class="btn btn-secondary" (click)="showWasteModal = false">Cancel</button>
        <button class="btn btn-warning" (click)="confirmWaste()">Mark as Wasted</button>
      </div>
    </div>
  </div>
</div>
